:root {
  /* Colors */
  --bg-dark: oklch(12.57% 0.039 264.43);
  --primary-blue: oklch(37.91% 0.242 263.95);
  --primary-light: oklch(55.23% 0.255 259.94);
  --grad-main: linear-gradient(-225deg, var(--primary-blue), var(--primary-light));
  --glow-color: rgba(255, 255, 255, 0.4);
  --text-muted: rgba(255, 255, 255, 0.6);
  /* Shared Transitions & Specs */
  --transition-fast: 0.2s ease;
  --radius-md: 8px;
  --grad-main: linear-gradient(-225deg, var(--primary-blue), var(--primary-light));
}

* {
  margin: 0;
  padding: 0;
  box-sizing: border-box;
}

body {
  min-height: 100vh;
  display: flex;
  align-items: center;
  justify-content: center;
  background: var(--bg-dark);
  font-family: "Proxima Nova", sans-serif;
  padding: 40px 20px;
}

.container {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(280px, 1fr));
  gap: 60px;
  max-width: 1400px;
  width: 100%;
}

.button-wrapper {
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 15px;
}
.button-wrapper .label {
  color: var(--text-muted);
  font-size: 13px;
  text-transform: uppercase;
  letter-spacing: 1.5px;
  font-weight: 600;
  font-family: sans-serif;
}

.btn {
  position: relative;
  padding: 20px 50px;
  font-size: 16px;
  font-weight: 700;
  letter-spacing: 0.5px;
  color: white;
  background-image: var(--grad-main);
  border: none;
  border-radius: var(--radius-md);
  cursor: pointer;
  overflow: hidden;
  text-transform: uppercase;
  transition: transform 0.1s ease;
  min-width: 220px;
  /* Shared pseudo-element behavior for hover effects */
  /* Specific Variants */
}
.btn:active {
  transform: scale(0.98);
}
.btn span {
  position: relative;
  z-index: 2;
  top: 2px;
  display: inline-block;
  text-shadow: 0 0.5px 0 rgba(0, 0, 0, 0.35), 0 1px 2px rgba(0, 0, 0, 0.25), 0 0 8px rgba(255, 255, 255, 0.12);
}
.btn::before {
  content: "";
  position: absolute;
  opacity: 0;
  transition: opacity var(--transition-fast);
}
.btn:hover::before {
  opacity: 1;
}
.btn.spotlight::before {
  inset: 0;
  background: radial-gradient(circle 100px at var(--x, 50%) var(--y, 50%), var(--glow-color), rgba(255, 255, 255, 0.1) 40%, transparent 70%);
}
.btn.magnetic::before {
  width: 150px;
  height: 150px;
  background: radial-gradient(circle, rgba(255, 255, 255, 0.5), rgba(255, 255, 255, 0.2) 40%, transparent 70%);
  top: var(--y, 50%);
  left: var(--x, 50%);
  transform: translate(-50%, -50%);
  pointer-events: none;
}
.btn.gradient-shift {
  background-image: linear-gradient(var(--angle, -225deg), var(--primary-blue), var(--primary-light));
  transition: background 0.3s ease;
}
.btn.gradient-shift::before {
  inset: 0;
  background: radial-gradient(circle 120px at var(--x, 50%) var(--y, 50%), rgba(100, 150, 255, 0.6), transparent 70%);
}
.btn.ripple::before {
  width: 20px;
  height: 20px;
  background: rgba(255, 255, 255, 0.5);
  border-radius: 50%;
  top: var(--y, 50%);
  left: var(--x, 50%);
  transform: translate(-50%, -50%);
  transition: width 0.5s ease, height 0.5s ease, opacity 0.5s ease;
}
.btn.ripple:hover::before {
  width: 300px;
  height: 300px;
  opacity: 0.15;
}
.btn.glass::before {
  inset: 0;
  background: linear-gradient(135deg, transparent 0%, rgba(255, 255, 255, 0) calc(var(--x, 50%) - 20%), rgba(255, 255, 255, 0.4) var(--x, 50%), rgba(255, 255, 255, 0) calc(var(--x, 50%) + 20%), transparent 100%);
}
.btn.border-light {
  background: var(--bg-dark);
}
.btn.border-light::before {
  inset: 0;
  border-radius: var(--radius-md);
  padding: 3px;
  background: radial-gradient(circle 150px at var(--x, 50%) var(--y, 50%), white, rgba(100, 150, 255, 0.5) 40%, transparent 70%);
  -webkit-mask: linear-gradient(#fff 0 0) content-box, linear-gradient(#fff 0 0);
  -webkit-mask-composite: xor;
  mask-composite: exclude;
}
.btn.border-light::after {
  content: "";
  position: absolute;
  inset: 3px;
  background-image: var(--grad-main);
  border-radius: 6px;
  z-index: 1;
}
.btn.particle::before {
  width: 200px;
  height: 200px;
  background: radial-gradient(circle, rgba(255, 255, 255, 0.6) 0%, rgba(255, 255, 255, 0.3) 20%, rgba(100, 150, 255, 0.2) 40%, transparent 70%);
  top: var(--y, 50%);
  left: var(--x, 50%);
  transform: translate(-50%, -50%);
  filter: blur(5px);
  transition: opacity 0.15s ease;
}
.btn.tilt {
  transform-style: preserve-3d;
  transform: perspective(1000px) rotateX(calc(var(--ry, 0) * 1deg)) rotateY(calc(var(--rx, 0) * 1deg));
  transition: transform 0.1s ease;
}
.btn.tilt::before {
  inset: 0;
  background: radial-gradient(circle 120px at var(--x, 50%) var(--y, 50%), rgba(255, 255, 255, 0.3), transparent 60%);
}
.btn.liquid::before {
  inset: -50%;
  background: radial-gradient(circle 100px at var(--x, 50%) var(--y, 50%), rgba(255, 255, 255, 0.6), rgba(150, 200, 255, 0.3) 30%, transparent 60%);
  filter: blur(20px);
  transition: opacity 0.3s ease;
}
.btn.neon::before {
  inset: -4px;
  background: radial-gradient(circle 100px at var(--x, 50%) var(--y, 50%), rgba(255, 255, 255, 0.8), rgba(100, 150, 255, 0.6) 30%, transparent 60%);
  border-radius: var(--radius-md);
  filter: blur(10px);
  z-index: 1;
}
.btn.neon:hover::before {
  animation: pulse 2s ease-in-out infinite;
}
.btn.crystalline::before {
  inset: 0;
  background: radial-gradient(circle 80px at calc(var(--x, 50%) - 10%) calc(var(--y, 50%) - 10%), rgba(255, 255, 255, 0.4), transparent 50%), radial-gradient(circle 60px at calc(var(--x, 50%) + 15%) calc(var(--y, 50%) + 15%), rgba(150, 200, 255, 0.3), transparent 50%);
}
.btn.plasma::before {
  inset: 0;
  background: radial-gradient(ellipse 150px 80px at var(--x, 50%) var(--y, 50%), rgba(255, 255, 255, 0.5), rgba(100, 180, 255, 0.3) 40%, transparent 70%);
  filter: blur(8px);
  mix-blend-mode: screen;
}

@keyframes pulse {
  0%, 100% {
    filter: blur(10px);
  }
  50% {
    filter: blur(15px);
  }
}
